# quality_probe.py — automated quality probe for Claude output classification
import anthropic
from dataclasses import dataclass

BASELINE_ACCURACY = 0.94  # calibrated from 30-day rolling average

@dataclass
class ProbeResult:
    correct: int
    total: int

    @property
    def accuracy(self) -> float:
        return self.correct / self.total if self.total > 0 else 0.0

    @property
    def severity(self) -> str:
        drop = BASELINE_ACCURACY - self.accuracy
        if drop > 0.15:
            return "P1"
        if drop > 0.05:
            return "P2"
        if drop > 0:
            return "P3"
        return "OK"

def run_quality_probe(client: anthropic.Anthropic, n: int = 50) -> ProbeResult:
    """Run n standardized prompts with known expected outputs."""
    test_cases = load_probe_test_cases()[:n]   # fixed test set; never changes
    correct = 0
    for tc in test_cases:
        resp = client.messages.create(
            model="claude-sonnet-5",
            max_tokens=50,
            messages=[{"role": "user", "content": tc["prompt"]}],
        )
        if tc["expected"] in resp.content[0].text:
            correct += 1
    return ProbeResult(correct=correct, total=n)

# Run probe on startup and every 5 minutes in production
result = run_quality_probe(anthropic.Anthropic())
if result.severity in ("P1", "P2"):
    alert_oncall(severity=result.severity,
                 message=f"Quality probe: {result.accuracy:.2%} vs baseline {BASELINE_ACCURACY:.2%}")
